Create NettingService that calculates net demand from gross demand minus available supply.

Create:
1. platform/src/main/java/com/auraboot/module/mrp/engine/NettingService.java

```java
@Service
@RequiredArgsConstructor
public class NettingService {
    private final InventoryQueryPort inventoryPort;

    /**
     * Calculate net demand for a material.
     * Formula: net = gross - (onHand - allocated) - inTransit + safetyStock
     * If net <= 0, no replenishment needed.
     */
    public BigDecimal calculateNetDemand(Long materialId, BigDecimal grossDemand) {
        BigDecimal onHand = inventoryPort.getOnHandQty(materialId, null); // null = all warehouses
        BigDecimal allocated = inventoryPort.getAllocatedQty(materialId);
        BigDecimal inTransit = inventoryPort.getInTransitQty(materialId);
        BigDecimal safetyStock = inventoryPort.getSafetyStock(materialId);

        // Available = onHand - allocated
        BigDecimal available = onHand.subtract(allocated);

        // Net = gross - available - inTransit + safetyStock
        BigDecimal net = grossDemand
            .subtract(available)
            .subtract(inTransit)
            .add(safetyStock != null ? safetyStock : BigDecimal.ZERO);

        return net.max(BigDecimal.ZERO); // never negative
    }

    /**
     * Check if a material needs replenishment.
     */
    public boolean needsReplenishment(Long materialId, BigDecimal grossDemand) {
        return calculateNetDemand(materialId, grossDemand).compareTo(BigDecimal.ZERO) > 0;
    }
}
```

