@RestController
@RequestMapping("/api/mrp")
@RequiredArgsConstructor
public class MrpController {
    private final MrpPlanningEngine engine;

    @PostMapping("/run")
    public ResponseEntity<MrpResult> runMrp(@RequestBody MrpRunRequest request) {
        // Convert request to demand entries (query sales orders or use materialIds)
        List<DemandEntry> demands = buildDemands(request);
        MrpResult result = engine.runMrp(demands, request.getHorizonDays());
        return ResponseEntity.ok(result);
    }
}
